# ============================================================================
# Auto-generated by Devin. Recreates all changed LFVideo files, commits & pushes.
# This script is PURE ASCII (file paths + contents are base64) so it is safe to
# copy-paste regardless of editor encoding. Save it anywhere and run:
#   powershell -ExecutionPolicy Bypass -File apply-lfvideo-changes.ps1
# Run it from INSIDE your LFVideo repo. Needs NO .patch file. Uses your own git creds.
# ============================================================================
[CmdletBinding()]
param([string]$Branch = 'main', [string]$Remote = 'origin')
$ErrorActionPreference = 'Stop'
function Fail($m) { Write-Host "[apply] ERROR: $m" -ForegroundColor Red; exit 1 }
function Step($m) { Write-Host "[apply] $m" -ForegroundColor Cyan }

& git rev-parse --is-inside-work-tree *> $null
if ($LASTEXITCODE -ne 0) { Fail "Not inside a git repository. cd into your LFVideo repo first." }
$repoRoot = (& git rev-parse --show-toplevel).Trim()
Step "Repo: $repoRoot"
$dirty = & git status --porcelain
if ($dirty) { Write-Host $dirty; Fail "Working tree is not clean. Commit or stash your changes first." }

Step "Checkout '$Branch' and pull --ff-only ..."
& git checkout $Branch; if ($LASTEXITCODE -ne 0) { Fail "git checkout $Branch failed." }
& git pull --ff-only;   if ($LASTEXITCODE -ne 0) { Fail "git pull --ff-only failed (branch diverged?)." }

$entries = @(
  @{ p = 'LndpbmRzdXJmL3dvcmtmbG93cy8wMS10b3BpYy1yZXNlYXJjaCAo6YCJ6aKY5YiG5p6QKS5tZA=='; c = '' },
  @{ p = 'LndpbmRzdXJmL3dvcmtmbG93cy8wMi1jb250ZW50LXBsYW5uaW5nICjlhoXlrrnnrZbliJIpLm1k'; c = '' },
  @{ p = 'Y29udGVudC1saWJyYXJ5L2VwMDItdmlkZW8tcmVuZGVyLzAyLXBsYW4vdHV0b3JpYWwgY29weS5tZA=='; c = '' },
  @{ p = 'Y29udGVudC1saWJyYXJ5L2VwMDItdmlkZW8tcmVuZGVyL0NPTlRFTlRMSUIubWQ='; c = '' },
  @{ p = 'c2NyaXB0cy9kZXZpbi1zeW5jLnBzMQ=='; c = '' },
  @{ p = 'c2hhcmVkL2RvY3MvcmVtb3Rpb24tc3BlYy5tZA=='; c = '' },
  @{ p = 'c2hhcmVkL3JvbGVzL2NvbnRlbnQvc3RyYXRlZ2lzdCjlhoXlrrnnrZbliJLluIgpLm1k'; c = '' },
  @{ p = 'c2hhcmVkL3JvbGVzL2NvbnRlbnQvdG9waWMtYW5hbHlzdCjpgInpopjliIbmnpDluIgpLm1k'; c = '' }
)

Step "Writing files ..."
foreach ($e in $entries) {
    $rel = [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($e.p))
    $bytes = [Convert]::FromBase64String($e.c)
    $full = Join-Path $repoRoot $rel
    $dir = Split-Path $full -Parent
    if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
    [System.IO.File]::WriteAllBytes($full, $bytes)
    Write-Host "  wrote $rel"
}

Step "Staging, committing, pushing ..."
& git add -A; if ($LASTEXITCODE -ne 0) { Fail "git add failed." }
& git commit -m "sync from devin: tutorial copy rewrite + roles/workflows A+B+C+D + devin-sync helper"
if ($LASTEXITCODE -ne 0) { Step "git commit returned non-zero (maybe nothing changed); continuing." }
& git push $Remote $Branch; if ($LASTEXITCODE -ne 0) { Fail "git push failed. Check credentials/network." }
& git log --oneline -3
Write-Host "[apply] SUCCESS: pushed to $Remote/$Branch" -ForegroundColor Green